READ game.js FULLY first.

Key locations:
- State variables/arrays: ~lines 1051-1065 (projectiles[] is at line 1061)
- createProjectile function: find it (creates projectile objects)
- Farmer shooting: ~lines 2515-2548 (pushes to projectiles array)
- updateProjectiles: ~lines 2553-2609 (movement + collision)
- renderProjectiles: ~lines 3325-3350
- Shield collision with projectiles: within updateProjectiles
- Incinerator beam interaction with projectiles: search for incinerator references

YOUR TASK: Replace the current `projectiles = []` array system with a pre-allocated bullet object pool. This is the foundation for the bullet-hell transformation.

### Implementation:

1. **Add the pool near the state variables section** (replace `let projectiles = []`):
```javascript
// Bullet pool for bullet-hell system
const BULLET_POOL_SIZE = 1500;
const bulletPool = new Array(BULLET_POOL_SIZE);
for (let i = 0; i < BULLET_POOL_SIZE; i++) {
  bulletPool[i] = { alive: false, x: 0, y: 0, vx: 0, vy: 0, speed: 0, angle: 0, life: 0, color: '#ff0', type: 'normal', radius: 2, grazed: false };
}

function spawnBullet(x, y, angle, speed, color, type, life) {
  for (let i = 0; i < BULLET_POOL_SIZE; i++) {
    if (!bulletPool[i].alive) {
      const b = bulletPool[i];
      b.alive = true;
      b.x = x; b.y = y;
      b.angle = angle;
      b.vx = Math.cos(angle) * speed;
      b.vy = Math.sin(angle) * speed;
      b.speed = speed;
      b.color = color || '#ffaa00';
      b.type = type || 'normal';
      b.life = life || 5;
      b.radius = type === 'large' ? 4 : 2;
      b.grazed = false;
      return b;
    }
  }
  return null;
}

function killBullet(b) { b.alive = false; }

function killAllBullets() {
  for (let i = 0; i < BULLET_POOL_SIZE; i++) bulletPool[i].alive = false;
}
```

