- streak < 10: yellow '#ffff88'
- streak < 15: orange '#ffaa44'
- streak >= 15: magenta '#ff44ff'

In audio.js, modify `playGraze` to accept streak parameter:
```javascript
function playGraze(multiplier, streak) {
  if (!initialized) return;
  const baseFreq = 523.25; // C5
  const semitone = 1.05946;
  const noteIndex = (streak || 0) % 12;
  const octave = Math.floor((streak || 0) / 12);
  const freq = baseFreq * Math.pow(semitone, noteIndex) * Math.pow(2, octave);

  const osc = ctx.createOscillator();
  const gain = ctx.createGain();
  osc.connect(gain);
  gain.connect(masterGain);

  osc.type = 'sine';
  osc.frequency.value = freq;
  gain.gain.setValueAtTime(0.08, ctx.currentTime);
  gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.12);

  osc.start();
  osc.stop(ctx.currentTime + 0.12);

  // Add harmony at streak 5+
  if (streak >= 5) {
    const osc2 = ctx.createOscillator();
    const gain2 = ctx.createGain();
    osc2.connect(gain2);
    gain2.connect(masterGain);
    osc2.type = 'sine';
    osc2.frequency.value = freq * 1.5; // perfect fifth
    gain2.gain.setValueAtTime(0.04, ctx.currentTime);
    gain2.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.1);
    osc2.start();
    osc2.stop(ctx.currentTime + 0.1);
  }

  // Add chord at streak 10+
  if (streak >= 10) {
    const osc3 = ctx.createOscillator();
    const gain3 = ctx.createGain();
    osc3.connect(gain3);
    gain3.connect(masterGain);
    osc3.type = 'sine';
    osc3.frequency.value = freq * 1.26; // major third
    gain3.gain.setValueAtTime(0.03, ctx.currentTime);
    gain3.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.1);
    osc3.start();
    osc3.stop(ctx.currentTime + 0.1);
  }
}
```

## FEATURE 4: Combo Timer Ring

Visualize the combo timer as a shrinking ring around the UFO.

In the rendering section, add a `renderComboRing()` function called in renderPlaying after renderUFO:

```javascript
function renderComboRing() {
  if (!ufo || comboCount <= 0 || comboTimer <= 0) return;

  const cx = Math.floor(ufo.x + ufo.w / 2);
  const cy = Math.floor(ufo.y + ufo.h / 2 + Math.sin(ufo.bobPhase) * 1.5);
  const ratio = comboTimer / COMBO_WINDOW; // 1.0 -> 0.0
  const radius = 18 + ratio * 6; // 24 at full, 18 at empty

  // Color: green -> yellow -> orange -> red
  let color;
  if (ratio > 0.75) color = '#44ff44';
  else if (ratio > 0.4) color = '#ffff44';
  else if (ratio > 0.15) color = '#ff8844';
  else color = '#ff4444';

  // Pulse speed increases as timer runs out
  const pulseRate = 4 + (1 - ratio) * 12;
  const pulse = Math.sin(stateTimer * pulseRate) * 0.2;

  ctx.globalAlpha = 0.4 + pulse + (1 - ratio) * 0.3;
  ctx.strokeStyle = color;
  ctx.lineWidth = 1;
  ctx.beginPath();
  // Draw arc proportional to remaining time
  const startAngle = -Math.PI / 2;
  const endAngle = startAngle + ratio * Math.PI * 2;
  ctx.arc(cx, cy, radius, startAngle, endAngle);
  ctx.stroke();

  // Combo count text at the ring
  if (comboCount >= 2) {
    const textX = cx + radius + 3;
    const textY = cy - 4;
    drawText('X' + comboCount, textX, textY, color, 1);
  }

  ctx.globalAlpha = 1;
}
```

