        ufo.y + ufo.h / 2 + Math.sin(angle) * 20,
        Math.cos(angle) * 40, Math.sin(angle) * 40,
        '#ff4444', 0.3, 1
      );
    }
  }
  comboCount = 0;
} else if (comboTimer <= 0) {
  comboCount = 0;
}
```

Call `renderComboRing()` in the playing render function after rendering the UFO.

