}
```

Also add the Earth timeline radio text as a third line in a green "radio" color:
```javascript
if (BALANCE.narrative.enabled && NARRATIVE.getTimeline) {
  const tl = NARRATIVE.getTimeline(level);
  if (tl) {
    // Draw year above the episode title
    drawTextCentered(tl.year, /* y above title */, '#448844', 1);
    // Draw radio intercept below subtitle
    drawTextCentered(tl.radio, /* y below subtitle */, '#44ff44', 1);
  }
}
```

