events.text:
[subagent] You are adding 3 level types with new rendering systems to "Udderly Abduction: Barrage" at "C:\Users\koalo\Desktop\Udderly Abduction Barrage".

READ game.js AND src/balance.js FULLY first. Pay special attention to:
- The waveModifier system (getWaveModifier, waveModifier, waveModifierData)
- startLevel() and the seamless level transition block
- renderPlaying() and the render pipeline order
- renderBackground(), renderGround()
- The boss system (boss variable, createBoss, updateBoss, renderBoss, bossFreezeTimer)
- The existing THEMES array
- Canvas: W=480, H=270, ctx is the offscreen canvas context

The modifier system is already built. `getWaveModifier(lv)` currently returns 'sniperAlley', 'swarm', or 'gauntlet' for specific waves, and null otherwise. You need to add 'fog', 'harvestMoon', and 'doubleTrouble' to this system.

Implement all 3:

## FEATURE 1: FOG BANK

**Wave assignment:** Waves 4, 9, 14, 19, 24, 29... (every 5th wave starting at 4, skipping boss waves)

Add to getWaveModifier:
```javascript
if (lv >= 4 && (lv - 4) % 5 === 0 && !isBossWave(lv)) return 'fog';
```
Make sure this doesn't conflict with existing assignments. Put it AFTER the gauntlet/sniperAlley/swarm checks so those take priority.

**Implementation:**

1. Add fog state to waveModifierData in startLevel:
```javascript
if (waveModifier === 'fog') {
  waveModifierData = { fogAlpha: 0, fogTarget: 0.85, fogRadius: 80 };
  levelBannerSubtitle = (levelBannerSubtitle || '') + ' FOG BANK';
}
```

2. In updatePlaying, ramp fog in:
```javascript
if (waveModifier === 'fog' && waveModifierData.fogAlpha !== undefined) {
  // Ramp fog in over 3 seconds
  waveModifierData.fogAlpha = Math.min(waveModifierData.fogTarget, waveModifierData.fogAlpha + dt / 3);
  // Fog radius: 80 normal, 110 when focusing
  waveModifierData.fogRadius = ufo && ufo.focusing ? 110 : 80;
}
```

3. Render fog overlay. Add a `renderFog()` function called AFTER all gameplay rendering but BEFORE HUD in renderPlaying:
```javascript
function renderFog() {
  if (waveModifier !== 'fog' || !waveModifierData.fogAlpha) return;
  if (!ufo) return;

  const cx = Math.floor(ufo.x + ufo.w / 2);
  const cy = Math.floor(ufo.y + ufo.h / 2 + Math.sin(ufo.bobPhase) * 1.5);
  const r = waveModifierData.fogRadius;
  const alpha = waveModifierData.fogAlpha;

  // Use a temporary canvas or draw fog manually:
  // Draw a dark overlay with a circular "hole"
  // Method: draw full dark rect, then use 'destination-out' composite to cut a circle

  // Save state
  ctx.save();

  // Draw dark fog overlay
  ctx.fillStyle = 'rgba(8, 8, 20, ' + alpha + ')';
  ctx.fillRect(0, 0, W, H);

  // Cut a radial hole at UFO position using destination-out
  ctx.globalCompositeOperation = 'destination-out';

  // Create radial gradient for soft edge
  const gradient = ctx.createRadialGradient(cx, cy, r * 0.4, cx, cy, r);
  gradient.addColorStop(0, 'rgba(0,0,0,1)');
  gradient.addColorStop(0.7, 'rgba(0,0,0,0.8)');
  gradient.addColorStop(1, 'rgba(0,0,0,0)');

  ctx.fillStyle = gradient;
  ctx.fillRect(cx - r, cy - r, r * 2, r * 2);

  ctx.restore(); // restores composite operation to default
}
```

WAIT - `destination-out` will erase everything including the game. We need a different approach. Use a fog canvas:

```javascript
// Create a fog canvas (do this once, near the other canvas setup)
const fogCanvas = document.createElement('canvas');
fogCanvas.width = W;
fogCanvas.height = H;
const fogCtx = fogCanvas.getContext('2d');

function renderFog() {
  if (waveModifier !== 'fog' || !waveModifierData.fogAlpha) return;
  if (!ufo) return;

  const cx = Math.floor(ufo.x + ufo.w / 2);
  const cy = Math.floor(ufo.y + ufo.h / 2 + Math.sin(ufo.bobPhase) * 1.5);
  const r = waveModifierData.fogRadius;
  const alpha = waveModifierData.fogAlpha;

  // Draw fog to separate canvas
  fogCtx.clearRect(0, 0, W, H);
  fogCtx.fillStyle = 'rgba(8, 8, 20, ' + alpha + ')';
  fogCtx.fillRect(0, 0, W, H);

  // Cut circular hole with radial gradient
  fogCtx.globalCompositeOperation = 'destination-out';
  const gradient = fogCtx.createRadialGradient(cx, cy, r * 0.3, cx, cy, r);
  gradient.addColorStop(0, 'rgba(0,0,0,1)');
  gradient.addColorStop(0.6, 'rgba(0,0,0,0.9)');
  gradient.addColorStop(1, 'rgba(0,0,0,0)');
  fogCtx.fillStyle = gradient;
  fogCtx.beginPath();
  fogCtx.arc(cx, cy, r, 0, Math.PI * 2);
  fogCtx.fill();
  fogCtx.globalCompositeOperation = 'source-over';

  // Also cut a dim hole around the beam if active (beam is visible through fog)
  if (ufo.beamActive) {
    fogCtx.globalCompositeOperation = 'destination-out';
    fogCtx.fillStyle = 'rgba(0,0,0,0.5)'; // partial clear
    const bx = ufo.x + ufo.w / 2;
    const by = ufo.y + ufo.h;
    const bw = ufo.beamW;
    const bh = ufo.beamH;
    fogCtx.fillRect(Math.floor(bx - bw/2), Math.floor(by), Math.ceil(bw), Math.ceil(bh));
    fogCtx.globalCompositeOperation = 'source-over';
  }

  // Composite fog onto main canvas
  ctx.drawImage(fogCanvas, 0, 0);
}
```

4. Add fog tutorial: In the tutorial triggers section, add:
```javascript
if (waveModifier === 'fog' && !tutorialSeen['fog']) {
  showTutorial('fog', 'FOCUS REVEALS MORE IN FOG', 3.0);
}
```

5. Force NIGHT theme during fog:
In startLevel and seamless transition, when fog is active, override the theme:
```javascript
// The theme comes from getLevelConfig. For fog waves, force NIGHT theme.
// In generateBackground call or theme selection, check waveModifier.
```
Actually, the cleanest way: in renderPlaying where `const theme = getLevelConfig(level).theme` is used, override:
```javascript
const theme = (waveModifier === 'fog') ? THEMES[2] : getLevelConfig(level).theme; // THEMES[2] is NIGHT
```

Add to balance.js:
```javascript
fog: {
  normalRadius: 80,
  focusRadius: 110,
  alpha: 0.85,
  rampTime: 3.0,
  beamVisible: true,
},
```
Put this inside waveModifiers.

## FEATURE 2: HARVEST MOON

**Wave assignment:** Waves 3, 13, 23, 33... (every 10th wave starting at 3, skipping boss/other modifiers)

Add to getWaveModifier (after fog check):
```javascript
if (lv >= 3 && (lv - 3) % 10 === 0 && !isBossWave(lv)) return 'harvestMoon';
```

**Implementation:**

1. Moon state in waveModifierData:
```javascript
if (waveModifier === 'harvestMoon') {
  waveModifierData = {
    moonX: -20,          // starts off-screen left
    moonY: 25,
    moonRadius: 15,
    moonSpeed: W / 90,   // crosses screen in ~90 seconds
    beamWidth: 100,      // ground spotlight width
  };
  levelBannerSubtitle = (levelBannerSubtitle || '') + ' HARVEST MOON';
}
```

2. Force NIGHT theme for harvest moon (same approach as fog).

3. Update moon in updatePlaying:
```javascript
if (waveModifier === 'harvestMoon' && waveModifierData.moonX !== undefined) {
  waveModifierData.moonX += waveModifierData.moonSpeed * dt;
  // Wrap around if needed (for very long waves)
  if (waveModifierData.moonX > W + 30) waveModifierData.moonX = -30;
}
```

4. Check if cow/farmer is in moonbeam. Add helper:
```javascript
function isInMoonbeam(entityX, entityW) {
  if (waveModifier !== 'harvestMoon') return false;
  const moonCx = waveModifierData.moonX;
  const halfBeam = waveModifierData.beamWidth / 2;
  const entityCx = entityX + entityW / 2;
  return Math.abs(entityCx - moonCx) < halfBeam;
}
```

5. Cow 2x scoring: In the COW_COLLECTED event listener for scoring, check moonbeam:
```javascript
// Modify the scoring listener (the first COW_COLLECTED listener):
// After calculating points, before adding to score:
if (waveModifier === 'harvestMoon' && isInMoonbeam(d.x - d.w/2, d.w)) {
  // 2x points for moonlit cows
  pts *= 2;
  // Visual indicator
  scorePopups.push(createScorePopup(d.x, d.y - 10, 'MOONLIT 2X!', '#ffcc44'));
}
```
Actually, the scoring listener uses d.points which is pre-calculated. We need to either modify the emit payload or add a post-multiplier. The simplest approach: add a separate listener that adds bonus points for moonlit cows:
```javascript
GameEvents.on(EVT.COW_COLLECTED, function(d) {
  if (waveModifier !== 'harvestMoon') return;
  if (isInMoonbeam(d.x - d.w/2, d.w)) {
    const bonus = d.points; // double the points (add the same amount again)
    score += bonus;
    scorePopups.push(createScorePopup(d.x, d.y - 10, 'MOONLIT 2X!', '#ffcc44'));
  }
});
```

6. Farmer aggression in moonbeam: In updateFarmers, when calculating shoot timer:
```javascript
if (waveModifier === 'harvestMoon' && isInMoonbeam(f.x, f.w)) {
  f.shootTimer *= 0.67; // 50% faster shooting in moonbeam
}
```

7. Render moon and moonbeam. Add renderHarvestMoon() called AFTER renderBackground but BEFORE entities:
```javascript
function renderHarvestMoon() {
  if (waveModifier !== 'harvestMoon') return;
  const md = waveModifierData;
  const mx = Math.floor(md.moonX);
  const my = Math.floor(md.moonY);
  const r = md.moonRadius;

  // Moon glow (large, faint)
  ctx.globalAlpha = 0.08;
  ctx.fillStyle = '#ffcc66';
  ctx.beginPath();
  ctx.arc(mx, my, r + 10, 0, Math.PI * 2);
  ctx.fill();

  // Moon body
  ctx.globalAlpha = 1;
  ctx.fillStyle = '#ffdd88';
  ctx.beginPath();
  ctx.arc(mx, my, r, 0, Math.PI * 2);
  ctx.fill();

  // Moon highlight
  ctx.fillStyle = '#ffeebb';
  ctx.beginPath();
  ctx.arc(mx - 3, my - 3, r * 0.6, 0, Math.PI * 2);
  ctx.fill();

  // Moonbeam cone (from moon to ground)
  const beamTop = my + r;
  const beamBottom = H - 32;
  const topWidth = 20;
  const bottomWidth = md.beamWidth;

  ctx.globalAlpha = 0.06;
  ctx.fillStyle = '#ffdd88';
  ctx.beginPath();
  ctx.moveTo(mx - topWidth/2, beamTop);
  ctx.lineTo(mx - bottomWidth/2, beamBottom);
  ctx.lineTo(mx + bottomWidth/2, beamBottom);
  ctx.lineTo(mx + topWidth/2, beamTop);
  ctx.closePath();
