| Level 3.mp3 | level-03.mp3 |
| ... up to Level 34.mp3 -> level-34.mp3 |

## STEPS:

### Step 1: Rename all files
Use bash `mv` commands to rename every file to clean lowercase kebab-case names in an `audio/` subdirectory. Create `audio/combos/` and `audio/levels/` directories.

Combo files rename to: `audio/combos/combo-04-mootastic.mp3`, `audio/combos/combo-05-mootacular.mp3`, etc.
Level files rename to: `audio/levels/level-01.mp3`, `audio/levels/level-02.mp3`, etc.

### Step 2: Wire combo sounds into audio.js

Add a function to AudioManager that loads and plays combo announcer clips:

```javascript
// Combo announcer audio
const comboAudioFiles = {
  4: 'audio/combos/combo-04-mootastic.mp3',
  5: 'audio/combos/combo-05-mootacular.mp3',
  6: 'audio/combos/combo-06-udder-mageddon.mp3',
  7: 'audio/combos/combo-07-cow-lateral-damage.mp3',
  8: 'audio/combos/combo-08-bovine-blitzkrieg.mp3',
  9: 'audio/combos/combo-09-milky-melee.mp3',
  10: 'audio/combos/combo-10-deca-moo.mp3',
  11: 'audio/combos/combo-11-herd-ocalypse.mp3',
  12: 'audio/combos/combo-12-dirty-dozen-dairy.mp3',
  13: 'audio/combos/combo-13-unlucky-for-them.mp3',
  14: 'audio/combos/combo-14-calf-catastrophe.mp3',
  15: 'audio/combos/combo-15-full-cream-frenzy.mp3',
  16: 'audio/combos/combo-16-sweet-sixteen-stampede.mp3',
  17: 'audio/combos/combo-17-pasture-prime.mp3',
  18: 'audio/combos/combo-18-steaks-are-high.mp3',
  20: 'audio/combos/combo-20-total-cow-nage.mp3',
  25: 'audio/combos/combo-25-legendary-herd.mp3',
};
const comboAudioBuffers = {};

// Load all combo audio on init
function loadComboAudio() {
  for (const [combo, file] of Object.entries(comboAudioFiles)) {
    fetch(file)
      .then(r => r.arrayBuffer())
      .then(buf => ctx.decodeAudioData(buf))
      .then(decoded => { comboAudioBuffers[combo] = decoded; })
      .catch(e => console.warn('Failed to load combo audio ' + file + ':', e));
  }
}

function playComboAnnouncer(comboCount) {
  if (!initialized || !ctx) return;
  // Find the highest matching combo threshold
  const thresholds = Object.keys(comboAudioBuffers).map(Number).sort((a, b) => b - a);
  for (const t of thresholds) {
    if (comboCount >= t && comboAudioBuffers[t]) {
      const source = ctx.createBufferSource();
      const gain = ctx.createGain();
      source.buffer = comboAudioBuffers[t];
      source.connect(gain);
      gain.connect(masterGain);
      gain.gain.value = 0.5; // announcer volume
      source.start();
      return;
    }
  }
}
```

Call `loadComboAudio()` inside the `init()` function after `loadAudioFiles()`.
Add `playComboAnnouncer` to the AudioManager return object.

### Step 3: Wire level start sounds into audio.js

Similar approach for level music stings:

```javascript
const levelAudioFiles = {};
for (let i = 1; i <= 34; i++) {
  const num = i < 10 ? '0' + i : '' + i;
  levelAudioFiles[i] = 'audio/levels/level-' + num + '.mp3';
}
const levelAudioBuffers = {};

function loadLevelAudio() {
  for (const [lv, file] of Object.entries(levelAudioFiles)) {
    fetch(file)
      .then(r => r.arrayBuffer())
      .then(buf => ctx.decodeAudioData(buf))
      .then(decoded => { levelAudioBuffers[lv] = decoded; })
      .catch(() => {}); // silently skip missing levels
  }
}

function playLevelStart(level) {
  if (!initialized || !ctx) return;
  // Play the level audio, or the highest available if exact level doesn't exist
  let lv = level;
  while (lv > 0 && !levelAudioBuffers[lv]) lv--;
  if (lv > 0 && levelAudioBuffers[lv]) {
    const source = ctx.createBufferSource();
    const gain = ctx.createGain();
    source.buffer = levelAudioBuffers[lv];
    source.connect(gain);
    gain.connect(masterGain);
    gain.gain.value = 0.4;
    source.start();
  }
}
```

Call `loadLevelAudio()` inside `init()`.
Add `playLevelStart` to the AudioManager return object.

### Step 4: Wire into game.js

**Combo announcer:** Find the combo listener in the COW_COLLECTED event handlers (around line 620) where `announcerText` is set. After setting the announcer text, add:
```javascript
AudioManager.playComboAnnouncer(d.combo);
```

**Level start:** Find `startLevel()` function. After the level banner is set, add:
```javascript
AudioManager.playLevelStart(level);
```

### IMPORTANT:
- Create the directories with mkdir -p
- Use bash mv to rename files (handle spaces in filenames with quotes)
- Don't convert to OGG (the files are small MP3s, 40-70KB each, fine as-is)
- Make sure audio.js loadComboAudio and loadLevelAudio don't crash if files are missing
- Actually do all the renames, edits to audio.js, and edits to game.js

